-- Eberron: описания предысторий из next.dnd.su (Eberron: Forge of the Artificer)
-- Источник: https://next.dnd.su/backgrounds/ — раздел "Eberron: Forge of the Artificer"

UPDATE rules.default_eberron_background
SET description = 'Ваша аберрантная метка дракона усложняла жизнь с момента её проявления. Возможно, вы успешно скрывали её большую часть жизни или избегали внимания. Или же вы сталкивались с подозрением и страхом, а возможно, и с открытой враждебностью одного или нескольких домов с драконьими метками. Вы могли вступить в ассоциацию с преступной организацией дома Тарканан (названной в честь одного из самых печально известных лидеров аберрантных меток во время Войны меток двадцать пять веков назад). Или же вы ищете свой путь в мире, полагаясь на свой ум и силу своей метки.'
WHERE code = 'ABERRANT_HEIR';

UPDATE rules.default_eberron_background
SET description = 'Вы связаны с одним из домов с драконьими метками, но у вас (пока) не проявилась драконья метка. Вы можете быть членом семьи по рождению или служащим дома без родственных связей. Вы зарабатывали на жизнь, выполняя дела дома, служа руками, ногами и глазами руководства дома в мире. У вас может быть много старых друзей, наставников и соперников в доме, которому вы служите, а также союзники или враги в других домах.'
WHERE code = 'HOUSE_AGENT';

UPDATE rules.default_eberron_background
SET description = 'Вы всю жизнь изучали утерянные и павшие культуры прошлого, посещали их руины, расшифровывали их письменные записи и исследовали сохранившиеся шедевры. Возможно, вы учились в Университете Моргрейв или подобном заведении, дополняя время в библиотеке полевыми работами среди древних руин в отдалённых местах. Одни археологи разграбляют сокровища прошлого в поисках богатства или славы, но большинство считают своим призванием учиться у прошлого. В любом случае, археологи Эберрона сочетают качества учёных историков с твёрдостью охотников за сокровищами.'
WHERE code = 'ARCHAEOLOGIST';

UPDATE rules.default_eberron_background
SET description = 'Вы выросли с уважением к семье и природе. Вы понимаете культуру Пяти наций, но не втягиваетесь в игры амбиций и статуса, в которые играют другие. Вы знаете красоту и силу, присущие жизни, тайны рождения и смерти и чудеса, происходящие между ними. Ваши познания в мире природы позволяют видеть сквозь ложь и обман городских жителей — и вы никогда не показываете, как много их уловок вы распознаёте.'
WHERE code = 'HOUSE_VADALIS_HEIR';

UPDATE rules.default_eberron_background
SET description = 'Благодаря связям с домом Галланда вы выросли, привыкнув к комфорту, оживлённым беседам, хорошему напитку и вкусной пище. Вы можете быть обаятельным и остроумным потомком дома, любящим лишь приятный вечер у тёплого очага. Или же вы интриган, использующий узы доверия и дружбы, чтобы подчинять других своей воле. Вы можете избрать путь приключенца, чтобы освоить кухни других культур и эпох, расширить сеть полезных контактов или заработать достаточно денег, чтобы открыть собственную таверну.'
WHERE code = 'HOUSE_GHALLANDA_HEIR';

UPDATE rules.default_eberron_background
SET description = 'Как наследник дома Денейт вы обучены бою — не искать его, но и не избегать. Вы усвоили важность долга, чести и законов, управляющих обществом, когда долг и честь терпят неудачу. Устанавливая своё имя в доме, вы могли работать телохранителем какого-нибудь незначительного сановника, наёмником или маршалом, охотящимся на беглецов. Теперь вы готовы занять подобающее положение в могущественнейшем из домов с драконьими метками.'
WHERE code = 'HOUSE_DENEITH_HEIR';

UPDATE rules.default_eberron_background
SET description = 'Дом Джораско учит, что болезни и травмы преследуют живых как призраки, лишая людей здоровья и долголетия. Вас научили способам борьбы с этими бедствиями — как магически, так и медикаментозно. Вы обучены применять эти навыки на службе другим — и следить за тем, чтобы вас всегда должным образом вознаграждали за эту услугу, обеспечивая здоровье и процветание дома Джораско. Вы можете быть добрым целителем, не выносящим боя, или бесстрастным специалистом, точно знающим, как вывести врага из строя или убить его точными ударами.'
WHERE code = 'HOUSE_JORASCO_HEIR';

UPDATE rules.default_eberron_background
SET description = 'Как потомок дома Каннит вы несёте гордое наследие. Каннит создаёт чудеса современного мира, и от вас ожидают вклада в продолжающийся успех дома через изобретения, учёность, бизнес или дипломатию. Единственное, что может вам помешать — глубокий раскол внутри самого дома. Чем скорее трое баронов решат, кто из них истинный глава дома (и у вас, без сомнения, есть свои предпочтения), тем скорее дом Каннит сможет занять подобающее ему положение лидерства среди всех домов с драконьими метками.'
WHERE code = 'HOUSE_CANNITH_HEIR';

UPDATE rules.default_eberron_background
SET description = 'Как наследник дома Кундарак вы гордитесь своей семьёй и её делом — охраной ценностей Хорвайра. Ваш дом всегда был лидером среди кланов Мрорских владений. Хотя он никогда не носил короны, за ним закрепилась репутация профессионализма, чести и порядка. Вы можете стремиться поддержать эту репутацию, ставить свою честь выше семейной или восстать против ожиданий дома и попирать требования чести.'
WHERE code = 'HOUSE_KUNDARAK_HEIR';

UPDATE rules.default_eberron_background
SET description = 'Как наследник дома Лирандар ветер — ваш союзник, море и небо — ваше владение. Несмотря на опустошение Последней войны, ваш дом на подъёме, поддерживаемый мастерством новой технологии дирижаблей. Вы могли провести раннюю карьеру на море матросом или штурманом; корабельным плотником; или членом гильдии Вызывателей дождя, манипулируя погодой и помогая с ирригацией и подобными общественными работами. Или вы могли быть среди первых в своём доме, поднявшихся в небо в составе экипажа дирижабля. Служба дому может призвать вас охотиться на пиратов в море Лхазаар, исследовать древние руины в поисках магических технологий для привязки стихийных сил или поднимать потерпевший крушение дирижабль в Землях скорби.'
WHERE code = 'HOUSE_LYRANDAR_HEIR';

UPDATE rules.default_eberron_background
SET description = 'Как член дома Медани ваша жизнь вращается вокруг обмана — не участия в нём, а предотвращения того, чтобы другие его творили. Вы видите окружающий мир как сложную паутину заговоров, интриг и контр-интриг. Оценивая спектр возможностей, вы используете интуицию, чтобы предсказывать угрозы для своих клиентов и защищаться от них задолго до того, как эти угрозы станут опасностью. Защита от клинка убийцы — работа для любого наёмника Денейт или головореза Тарашк; убедиться, что никто никогда не обнажит этот клинок — путь Медани.'
WHERE code = 'HOUSE_MEDANI_HEIR';

UPDATE rules.default_eberron_background
SET description = 'До Последней войны влияние Ориен охватывало Хорвайр, а торговые дороги и молниерельсы были жизненными артериями процветающего королевства. Но война перерезала эти артерии, оставив Галифар мёртвым, а дом Ориен обескровленным. Хотя курьеры и перевозчики дома по-прежнему перемещают товары по обе стороны континента, восстановление маршрутов через Земли скорби остаётся главным приоритетом дома. А пока искатели приключений Ориен могут служить дому, расследуя исчезновения курьеров, возвращая товары, похищенные из караванов, и устраняя сбои на молниерельсе.'
WHERE code = 'HOUSE_ORIEN_HEIR';

UPDATE rules.default_eberron_background
SET description = 'Почти тридцать веков ваша семья работала над поддержанием порядка. Общение — это нить, связывающая цивилизацию, и ваши предки улаживали споры государей и помогали домам с драконьими метками найти место в мире. Немногие понимают, какое влияние дом Сивис оказал на облик современной эпохи — так же как немногие знают, как часто королевский советник обладает большей властью, чем сам правитель. Пока другие дома с драконьими метками сражаются за славу и признание, дом Сивис ведёт долгую игру тонкого влияния за кулисами, сохраняя порядок среди хаоса бесконечных интриг.'
WHERE code = 'HOUSE_SIVIS_HEIR';

UPDATE rules.default_eberron_background
SET description = 'Наследники других домов ведут жизнь в роскоши, но в доме Тарашк вы с раннего возраста научились самостоятельности. Чего вашему молодому дому не хватает в ресурсах, он восполняет духом и решимостью. У Тарашка есть судьба, которую нужно исполнить, и в ней есть место для вас. Будь то в бою или в общении, вы научились играть роль охотника: изучать врагов, использовать их слабости и делать всё необходимое для победы.'
WHERE code = 'HOUSE_THARASHK_HEIR';

UPDATE rules.default_eberron_background
SET description = 'Учитывая короткую историю дома Туранни и его фокус на шпионаже, его лидеры ожидают, что вы будете продвигать интересы дома при каждой возможности. В годы становления дома как независимой организации каждое ваше действие внимательно отслеживалось. Это не значит, что каждый наследник Туранни должен активно шпионить по указанию старейшин дома. Но даже самые замкнутые художники и ремесленники дома должны следить за текущими политическими событиями и передавать или собирать информацию по запросу.'
WHERE code = 'HOUSE_THURANNI_HEIR';

UPDATE rules.default_eberron_background
SET description = 'Хотя вы видели богатство, славу и красоту как дитя дома Фиарлан, вы считаете знание (и даруемую им власть) величайшим сокровищем. Вы можете искать эту власть как художник или исполнитель, всегда настороже к секретам даже когда услаждаете мир историей, песней, акробатикой или искусством. Или вы можете поддерживать связи с тайным шпионским крылом вашего дома: Змеиным столом.'
WHERE code = 'HOUSE_PHIARLAN_HEIR';

UPDATE rules.default_eberron_background
SET description = 'Гонимы безграничным любопытством, вы отточили таланты расследования и дедукции, исследуя тайны, отыскивая пропавших людей, возвращая украденные вещи, проливая свет на коррупцию и заговоры или раскрывая преступления. Как сыскной вы могли зарабатывать случайными заказами, служить в сыскном агентстве (возможно, лицензированном домом с драконьей меткой, как Медани или Тарашк), писать для газеты или работать в полиции.'
WHERE code = 'INQUISITIVE';
